using System; using UnityEngine; using UnityEngine.UI; namespace DungeonSlash { public sealed class PerkChoiceItem : MonoBehaviour { [SerializeField] private Button button; [SerializeField] private Text label; public void Configure(Button newButton, Text newLabel) { button = newButton; label = newLabel; } public void Bind(PerkData perk, Action<PerkData> selected) { label.text = $"{perk.displayName}\n<size=13>{perk.description}</size>"; button.onClick.RemoveAllListeners(); button.onClick.AddListener(() => selected(perk)); } } }
